qReadOnly=1,HostReqWriteOnly=2,HostReqReadWrite=3}host_req_type_e;// Enum representing clock frequency difference on 2 clockstypedefenumbit[1:0]{ClkFreqDiffNone,ClkFreqDiffSmall,ClkFreqDiffBig,ClkFreqDiffAny}clk_freq_diff_e;// return the smaller value of 2 inputsfunctionautomaticintmin2(inta,intb);return(a<b)?a:b;endfunction// return the bigger value of 2 inputsfunctionautomaticintmax2(inta,intb);return(a>b)?a:b;endfunction// return the biggest value within the given queue of integers.functionautomaticintmax(constrefintint_q[$]);`DV_CHECK_GT_FATAL(int_q.size(),0,"max function cannot accept an empty queue of integers!",$sformatf("%m"))// Assign the first value from the queue in case of negative integers.max=int_q[0];foreach(int_q[i])max=max2(max,int_q[i]);returnmax;endfunction// get absolute value of the input. Usage: absolute(val) or absolute(a - b)functionautomaticuintabsolute(intval);returnval>=0?val:-val;endfunction// endian swaps a 32-bit data wordfunctionautomaticlogic[31:0]endian_swap(logic[31:0]data);return{<<8{data}};endfunction// endian swaps bytes at a word granularity, while preserving overall word ordering.//// e.g. if `arr[] = '{'h0, 'h1, 'h2, 'h3, 'h4, 'h5, 'h6, 'h7}`, this function will produce://      `'{'h3, 'h2, 'h1, 'h0, 'h7, 'h6, 'h5, 'h4}`functionautomaticvoidendian_swap_byte_arr(refbit[7:0]arr[]);arr={<<byte{arr}};arr={<<32{arr}};endfunction`ifdefUVM// Simple function to set max errors before quitting simfunctionautomaticvoidset_max_quit_count(intn);uvm_report_serverreport_server=uvm_report_server::get_server();report_server.set_max_quit_count(n);endfunction// return if uvm_fatal occurredfunctionautomaticbithas_uvm_fatal_occurred();uvm_report_serverreport_server=uvm_report_server::get_server();returnreport_server.get_severity_count(UVM_FATAL)>0;endfunction// get masked data based on provided byte mask; if csr reg handle is provided (optional) then// masked bytes from csr's mirrored value are returned, else masked bytes are 0'sfunctionautomaticb