tracts the address and size of a const symbol in a SW test (supplied as an ELF file).//// Used by a testbench to modify the given symbol in an executable (elf) generated for an embedded// CPU within the DUT. This function only returns the extracted address and size of the symbol// using the readelf utility. Readelf comes with binutils, a package typically available on linux// machines. If not available, the assumption is, it can be relatively easily installed.// The actual job of writing the new value into the symbol is handled externally (often via a// backdoor mechanism to write the memory).// Return 1 on success and 0 on failure.functionautomaticbitsw_symbol_get_addr_size(inputstringelf_file,inputstringsymbol,inputbitdoes_not_exist_ok,outputlongintunsignedaddr,outputlongintunsignedsize);stringescaped_symbol="";stringsymbol_for_filename="";if(elf_file=="")`uvm_fatal($sformatf("%m"),"'elf_file' argument cannot be an empty string")if(symbol=="")`uvm_fatal($sformatf("%m"),"'symbol' argument cannot be an empty string")// If the symbol has special characters, such as '$', escape it for the cmd below, but when// creating the file, omit the special characters entirely.foreach(symbol[i])beginif(symbol[i]=="$")beginescaped_symbol={escaped_symbol,"\\",symbol[i]};endelsebeginescaped_symbol={escaped_symbol,symbol[i]};symbol_for_filename={symbol_for_filename,symbol[i]};endendbeginintret;stringline;intout_file_d=0;stringout_file=$sformatf("%0s.dat",symbol_for_filename);stringcmd=$sformatf(// use `--wide` to avoid truncating the output, in case of long symbol name// `\s%0s$` ensures we are looking for an exact match, with no pre- or postfixes."/usr/bin/readelf -s --wide %0s | grep \"\\s%0s$\" | awk \'{print $2\" \"$3}\' > %0s",elf_file,escaped_symbol,out_file);// TODO #3838: shell pipes are bad 'mkay?ret=$system(cmd);`DV_CHECK_EQ_FATAL(ret,0,$sformatf("Command \"%0s\" failed with exit code %0d",cmd,ret),$sformatf("%m"))out_file_d=$fopen(out_file,"r");`DV_CHECK_FATAL(out_file_d,$sformatf("Failed to open \"%0s\"",out_file),$sformatf("%m"))ret=$fgets(line,out_file_d);// If the symbol did not exist in the elf (empty file), and we are ok with that, then return.if(!ret&&does_not_exist_ok)return0;`DV_CHECK_FATAL(ret,$sformatf("Failed to read line from \"%0s\"",out_file),$sformatf("%m"))// The first line should have the addr in hex followed by its size as integer.ret=$sscanf(line,"%h %d",addr,size);`DV_CHECK_EQ_FATAL(ret,2,$sformatf("Failed to extract {addr size} from line \"%0s\"",line),$sformatf("%m"))// Attempt to read the next line should be met with EOF.void'($fgets(line,out_file_d));ret=$feof(out_file_d);`DV_CHECK_FATAL(ret,$sformatf("EOF expected to be reached for \"%0s\"",out_file),$sformatf("%m"))$fclose(out_file_d);ret=$system($sformatf("rm -rf %0s",out_file));`DV_CHECK_EQ_FATAL(ret,0,$sformatf("Failed to delete \"%0s\"",out_file),$sformatf("%m"))return1;endendfunction// Reads VMEM file contents into a queue of data.//// TODO: Add support for non-contiguous memory.// TODO: Add support for ECC bits.// TODO: Add support for non-BUS_DW sized VMEM data.// vmem_file: Path to VMEM image, compatible with $readmemh mathod.// vmem_data: A queue of BUS_DW sized data returned to the caller.functionautomaticvoidread_vmem(inputstringvmem_file,outputlogic[bus_params_pkg::BUS_DW-1:0]vmem_data[$]);intfd;uvm_reg_addr_tlast_addr;stringtext,msg="\n",lines[$];fd=$fopen(vmem_file,"r");`DV_CHECK_FATAL(fd,$sformatf("Failed to open \"%0s\"",vmem_file),$sformatf("%m"))while(!$feof(fd))beginstringline;void'($fgets(line,fd));line=str_utils_pkg::str_strip(line);if(line=="")continue;text={text,line,"\n"};end$fclose(fd);`DV_CHECK_STRNE_FATAL(text,"",,$sformatf("%m"))// Remove all block and single comments.text=str_utils_pkg::str_remove_sections(.s(text),.start_delim("/*"),.end_delim("*/"));text=str_utils_pkg::str_remove_sections(.s(text),.start_delim("//"),.end_delim("\n"),.remove_end_delim(0));vmem_data.delete();str_utils_pkg::str_split(text,lines,"\n");foreach(line